abstract class PaymentGateway {
  Future<PaymentResult> processPayment({
    required double amount,
    required String currency,
    required String userId,
    Map<String, dynamic>? metadata,
  });

  Future<bool> verifyTransaction(String transactionId);
  Future<PaymentResult> refundTransaction(String transactionId);
}

class StripeGateway implements PaymentGateway {
  final PaymentConfig config;
  final String apiUrl = 'https://api.stripe.com/v1';

  StripeGateway(this.config);

  String _getAuthHeader() {
    final credentials = base64Encode(utf8.encode('${config.stripeSecretKey}:'));
    return 'Basic $credentials';
  }

  @override
  Future<PaymentResult> processPayment({
    required double amount,
    required String currency,
    required String userId,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      final response = await http.post(
        Uri.parse('$apiUrl/payment_intents'),
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'amount': (amount * 100).toInt().toString(),
          'currency': currency.toLowerCase(),
          'metadata[userId]': userId,
          if (metadata != null)
            ...metadata.map((key, value) => MapEntry('metadata[$key]', value.toString())),
        },
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        final transaction = PaymentTransaction(
          id: data['id'],
          userId: userId,
          amount: amount,
          currency: currency,
          method: PaymentMethod.stripe,
          status: _mapStripeStatus(data['status']),
          timestamp: DateTime.now(),
          metadata: metadata ?? {},
        );

        return PaymentResult(
          success: true,
          transactionId: data['id'],
          transaction: transaction,
        );
      } else {
        final error = json.decode(response.body);
        return PaymentResult(
          success: false,
          errorMessage: error['error']['message'],
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Stripe payment failed: $e',
      );
    }
  }

  @override
  Future<bool> verifyTransaction(String transactionId) async {
    try {
      final response = await http.get(
        Uri.parse('$apiUrl/payment_intents/$transactionId'),
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
        },
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        return data['status'] == 'succeeded';
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  @override
  Future<PaymentResult> refundTransaction(String transactionId) async {
    try {
      final response = await http.post(
        Uri.parse('$apiUrl/refunds'),
        headers: {
          'Authorization': 'Bearer ${config.stripeSecretKey}',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: {
          'payment_intent': transactionId,
        },
      );

      if (response.statusCode == 200) {
        return PaymentResult(success: true, transactionId: transactionId);
      } else {
        final error = json.decode(response.body);
        return PaymentResult(
          success: false,
          errorMessage: error['error']['message'],
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Refund failed: $e',
      );
    }
  }

  TransactionStatus _mapStripeStatus(String status) {
    switch (status) {
      case 'succeeded':
        return TransactionStatus.completed;
      case 'processing':
        return TransactionStatus.processing;
      case 'requires_payment_method':
      case 'requires_confirmation':
        return TransactionStatus.pending;
      case 'canceled':
        return TransactionStatus.cancelled;
      default:
        return TransactionStatus.failed;
    }
  }
}

class PayPalGateway implements PaymentGateway {
  final PaymentConfig config;
  String? _accessToken;
  DateTime? _tokenExpiry;

  PayPalGateway(this.config);

  String get _baseUrl => config.sandboxMode
      ? 'https://api-m.sandbox.paypal.com'
      : 'https://api-m.paypal.com';

  Future<String> _getAccessToken() async {
    if (_accessToken != null &&
        _tokenExpiry != null &&
        DateTime.now().isBefore(_tokenExpiry!)) {
      return _accessToken!;
    }

    final credentials =
        base64Encode(utf8.encode('${config.paypalClientId}:${config.paypalSecret}'));

    final response = await http.post(
      Uri.parse('$_baseUrl/v1/oauth2/token'),
      headers: {
        'Authorization': 'Basic $credentials',
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: {'grant_type': 'client_credentials'},
    );

    if (response.statusCode == 200) {
      final data = json.decode(response.body);
      _accessToken = data['access_token'];
      _tokenExpiry = DateTime.now().add(Duration(seconds: data['expires_in']));
      return _accessToken!;
    } else {
      throw Exception('Failed to get PayPal access token');
    }
  }

  @override
  Future<PaymentResult> processPayment({
    required double amount,
    required String currency,
    required String userId,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      final token = await _getAccessToken();

      final orderData = {
        'intent': 'CAPTURE',
        'purchase_units': [
          {
            'amount': {
              'currency_code': currency.toUpperCase(),
              'value': amount.toStringAsFixed(2),
            },
            'custom_id': userId,
          }
        ],
      };

      final response = await http.post(
        Uri.parse('$_baseUrl/v2/checkout/orders'),
        headers: {
          'Authorization': 'Bearer $token',
          'Content-Type': 'application/json',
        },
        body: json.encode(orderData),
      );

      if (response.statusCode == 201) {
        final data = json.decode(response.body);
        final transaction = PaymentTransaction(
          id: data['id'],
          userId: userId,
          amount: amount,
          currency: currency,
          method: PaymentMethod.paypal,
          status: TransactionStatus.pending,
          timestamp: DateTime.now(),
          metadata: metadata ?? {},
        );

        return PaymentResult(
          success: true,
          transactionId: data['id'],
          transaction: transaction,
        );
      } else {
        final error = json.decode(response.body);
        return PaymentResult(
          success: false,
          errorMessage: error['message'] ?? 'PayPal payment failed',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'PayPal payment failed: $e',
      );
    }
  }

  @override
  Future<bool> verifyTransaction(String transactionId) async {
    try {
      final token = await _getAccessToken();

      final response = await http.get(
        Uri.parse('$_baseUrl/v2/checkout/orders/$transactionId'),
        headers: {
          'Authorization': 'Bearer $token',
        },
      );

      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        return data['status'] == 'COMPLETED';
      }
      return false;
    } catch (e) {
      return false;
    }
  }

  @override
  Future<PaymentResult> refundTransaction(String transactionId) async {
    try {
      final token = await _getAccessToken();

      final response = await http.post(
        Uri.parse('$_baseUrl/v2/payments/captures/$transactionId/refund'),
        headers: {
          'Authorization': 'Bearer $token',
          'Content-Type': 'application/json',
        },
        body: json.encode({}),
      );

      if (response.statusCode == 201) {
        return PaymentResult(success: true, transactionId: transactionId);
      } else {
        final error = json.decode(response.body);
        return PaymentResult(
          success: false,
          errorMessage: error['message'] ?? 'Refund failed',
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Refund failed: $e',
      );
    }
  }
}

class InAppPurchaseManager {
  final InAppPurchase _inAppPurchase = InAppPurchase.instance;
  final StreamController<List<PurchaseDetails>> _purchaseController =
      StreamController<List<PurchaseDetails>>.broadcast();

  Stream<List<PurchaseDetails>> get purchaseStream => _purchaseController.stream;
  StreamSubscription<List<PurchaseDetails>>? _subscription;

  Future<void> initialize() async {
    final available = await _inAppPurchase.isAvailable();
    if (!available) {
      throw Exception('In-app purchases not available');
    }

    if (Platform.isIOS) {
      final iosPlatform = _inAppPurchase
          .getPlatformAddition<InAppPurchaseStoreKitPlatformAddition>();
      await iosPlatform.setDelegate(ExamplePaymentQueueDelegate());
    }

    _subscription = _inAppPurchase.purchaseStream.listen(
      (purchases) {
        _handlePurchaseUpdates(purchases);
      },
      onError: (error) {
        debugPrint('Purchase stream error: $error');
      },
    );
  }

  Future<List<ProductDetails>> getProducts(List<String> productIds) async {
    final response = await _inAppPurchase.queryProductDetails(productIds.toSet());

    if (response.error != null) {
      throw Exception('Failed to query products: ${response.error}');
    }

    return response.productDetails.map((product) {
      return ProductDetails(
        id: product.id,
        title: product.title,
        description: product.description,
        price: double.parse(product.rawPrice.toString()),
        currency: product.currencyCode,
        priceString: product.price,
      );
    }).toList();
  }

  Future<PaymentResult> purchaseProduct(String productId) async {
    final productDetailsResponse =
        await _inAppPurchase.queryProductDetails({productId});

    if (productDetailsResponse.productDetails.isEmpty) {
      return PaymentResult(
        success: false,
        errorMessage: 'Product not found',
      );
    }

    final productDetails = productDetailsResponse.productDetails.first;
    final purchaseParam = PurchaseParam(productDetails: productDetails);

    try {
      final result = await _inAppPurchase.buyNonConsumable(
        purchaseParam: purchaseParam,
      );

      return PaymentResult(
        success: result,
        errorMessage: result ? null : 'Purchase failed',
      );
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Purchase error: $e',
      );
    }
  }

  Future<PaymentResult> purchaseSubscription(String productId) async {
    final productDetailsResponse =
        await _inAppPurchase.queryProductDetails({productId});

    if (productDetailsResponse.productDetails.isEmpty) {
      return PaymentResult(
        success: false,
        errorMessage: 'Product not found',
      );
    }

    final productDetails = productDetailsResponse.productDetails.first;
    final purchaseParam = PurchaseParam(productDetails: productDetails);

    try {
      final result = await _inAppPurchase.buyNonConsumable(
        purchaseParam: purchaseParam,
      );

      return PaymentResult(
        success: result,
        errorMessage: result ? null : 'Subscription failed',
      );
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Subscription error: $e',
      );
    }
  }

  void _handlePurchaseUpdates(List<PurchaseDetails> purchases) async {
    for (var purchase in purchases) {
      if (purchase.status == PurchaseStatus.purchased ||
          purchase.status == PurchaseStatus.restored) {
        final valid = await _verifyPurchase(purchase);
        if (valid) {
          await _deliverProduct(purchase);
        }
      }

      if (purchase.pendingCompletePurchase) {
        await _inAppPurchase.completePurchase(purchase);
      }
    }

    _purchaseController.add(purchases);
  }

  Future<bool> _verifyPurchase(PurchaseDetails purchase) async {
    return true;
  }

  Future<void> _deliverProduct(PurchaseDetails purchase) async {
    debugPrint('Delivering product: ${purchase.productID}');
  }

  Future<void> restorePurchases() async {
    await _inAppPurchase.restorePurchases();
  }

  void dispose() {
    _subscription?.cancel();
    _purchaseController.close();
  }
}

