class SecurePaymentStorage {
  static const MethodChannel _channel = MethodChannel('secure_payment_storage');

  Future<void> saveTransactionData(PaymentTransaction transaction) async {
    final encryptedData = _encryptData(json.encode(transaction.toJson()));
    await _channel.invokeMethod('saveSecure', {
      'key': 'transaction_${transaction.id}',
      'value': encryptedData,
    });
  }

  Future<PaymentTransaction?> getTransactionData(String transactionId) async {
    try {
      final encryptedData = await _channel.invokeMethod('getSecure', {
        'key': 'transaction_$transactionId',
      });

      if (encryptedData == null) return null;

      final decryptedData = _decryptData(encryptedData);
      return PaymentTransaction.fromJson(json.decode(decryptedData));
    } catch (e) {
      debugPrint('Error retrieving transaction: $e');
      return null;
    }
  }

  String _encryptData(String data) {
    final bytes = utf8.encode(data);
    final digest = sha256.convert(bytes);
    return base64Encode(bytes);
  }

  String _decryptData(String encryptedData) {
    final bytes = base64Decode(encryptedData);
    return utf8.decode(bytes);
  }
}

class PaymentProcessor {
  final PaymentConfig config;
  final Map<PaymentMethod, PaymentGateway> _gateways = {};
  final InAppPurchaseManager _inAppPurchaseManager = InAppPurchaseManager();
  final SecurePaymentStorage _storage = SecurePaymentStorage();
  final StreamController<PaymentTransaction> _transactionController =
      StreamController<PaymentTransaction>.broadcast();

  Stream<PaymentTransaction> get transactionStream =>
      _transactionController.stream;

  PaymentProcessor(this.config) {
    _gateways[PaymentMethod.stripe] = StripeGateway(config);
    _gateways[PaymentMethod.paypal] = PayPalGateway(config);
  }

  Future<void> initialize() async {
    await _inAppPurchaseManager.initialize();
  }

  Future<PaymentResult> processPayment({
    required double amount,
    required String currency,
    required String userId,
    required PaymentMethod method,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      if (!_validateAmount(amount)) {
        return PaymentResult(
          success: false,
          errorMessage: 'Invalid payment amount',
        );
      }

      if (!_validateCurrency(currency)) {
        return PaymentResult(
          success: false,
          errorMessage: 'Invalid currency code',
        );
      }

      final gateway = _gateways[method];
      if (gateway == null) {
        return PaymentResult(
          success: false,
          errorMessage: 'Payment method not supported',
        );
      }

      final result = await gateway.processPayment(
        amount: amount,
        currency: currency,
        userId: userId,
        metadata: metadata,
      );

      if (result.success && result.transaction != null) {
        await _storage.saveTransactionData(result.transaction!);
        _transactionController.add(result.transaction!);

        await _notifyBackend(result.transaction!);
      }

      return result;
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Payment processing error: $e',
      );
    }
  }

  Future<PaymentResult> purchaseInAppProduct(String productId) async {
    final result = await _inAppPurchaseManager.purchaseProduct(productId);
    return result;
  }

  Future<PaymentResult> purchaseSubscription(String subscriptionId) async {
    final result = await _inAppPurchaseManager.purchaseSubscription(subscriptionId);
    return result;
  }

  Future<List<ProductDetails>> getAvailableProducts(
      List<String> productIds) async {
    return await _inAppPurchaseManager.getProducts(productIds);
  }

  Future<bool> verifyTransaction(
      String transactionId, PaymentMethod method) async {
    final gateway = _gateways[method];
    if (gateway == null) return false;

    return await gateway.verifyTransaction(transactionId);
  }

  Future<PaymentResult> refundPayment(
      String transactionId, PaymentMethod method) async {
    final gateway = _gateways[method];
    if (gateway == null) {
      return PaymentResult(
        success: false,
        errorMessage: 'Payment method not supported',
      );
    }

    final result = await gateway.refundTransaction(transactionId);

    if (result.success) {
      final transaction = await _storage.getTransactionData(transactionId);
      if (transaction != null) {
        final refundedTransaction = PaymentTransaction(
          id: transaction.id,
          userId: transaction.userId,
          amount: transaction.amount,
          currency: transaction.currency,
          method: transaction.method,
          status: TransactionStatus.refunded,
          timestamp: DateTime.now(),
          metadata: transaction.metadata,
        );

        await _storage.saveTransactionData(refundedTransaction);
        _transactionController.add(refundedTransaction);
      }
    }

    return result;
  }

  Future<void> restorePurchases() async {
    await _inAppPurchaseManager.restorePurchases();
  }

  bool _validateAmount(double amount) {
    return amount > 0 && amount < 1000000;
  }

  bool _validateCurrency(String currency) {
    final validCurrencies = ['USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD'];
    return validCurrencies.contains(currency.toUpperCase());
  }

  Future<void> _notifyBackend(PaymentTransaction transaction) async {
    try {
      await http.post(
        Uri.parse('${config.backendUrl}/transactions'),
        headers: {'Content-Type': 'application/json'},
        body: json.encode(transaction.toJson()),
      );
    } catch (e) {
      debugPrint('Failed to notify backend: $e');
    }
  }

  void dispose() {
    _inAppPurchaseManager.dispose();
    _transactionController.close();
  }
}

class ApplePayHandler {
  static const MethodChannel _channel = MethodChannel('apple_pay');

  Future<bool> isAvailable() async {
    if (!Platform.isIOS) return false;
    try {
      return await _channel.invokeMethod('canMakePayments') ?? false;
    } catch (e) {
      return false;
    }
  }

  Future<PaymentResult> processPayment({
    required double amount,
    required String currency,
    required String merchantId,
    required String countryCode,
  }) async {
    try {
      final result = await _channel.invokeMethod('processPayment', {
        'amount': amount,
        'currency': currency,
        'merchantId': merchantId,
        'countryCode': countryCode,
      });

      if (result['success'] == true) {
        return PaymentResult(
          success: true,
          transactionId: result['transactionId'],
        );
      } else {
        return PaymentResult(
          success: false,
          errorMessage: result['error'],
        );
      }
    } catch (e) {
      return PaymentResult(
        success: false,
        errorMessage: 'Apple Pay failed: $e',
      );
    }
  }
}

