class PaymentAnalytics {
  final List<PaymentTransaction> _transactions = [];

  void recordTransaction(PaymentTransaction transaction) {
    _transactions.add(transaction);
  }

  double getTotalRevenue() {
    return _transactions
        .where((t) => t.status == TransactionStatus.completed)
        .fold(0.0, (sum, t) => sum + t.amount);
  }

  int getSuccessfulTransactionCount() {
    return _transactions
        .where((t) => t.status == TransactionStatus.completed)
        .length;
  }

  int getFailedTransactionCount() {
    return _transactions.where((t) => t.status == TransactionStatus.failed).length;
  }

  double getSuccessRate() {
    if (_transactions.isEmpty) return 0.0;
    return getSuccessfulTransactionCount() / _transactions.length * 100;
  }

  Map<String, dynamic> getAnalytics() {
    return {
      'totalRevenue': getTotalRevenue(),
      'totalTransactions': _transactions.length,
      'successfulTransactions': getSuccessfulTransactionCount(),
      'failedTransactions': getFailedTransactionCount(),
      'successRate': getSuccessRate(),
    };
  }
}